// frontend/src/components/SearchForm.js
import React, { useState, useEffect } from 'react';
import axios from '../api';

const SearchForm = () => {
  const [districts, setDistricts] = useState([]);
  const [talukas, setTalukas] = useState([]);
  const [villages, setVillages] = useState([]);

  const [selectedDistrict, setSelectedDistrict] = useState('');
  const [selectedTaluka, setSelectedTaluka] = useState('');
  const [selectedVillage, setSelectedVillage] = useState('');
  const [surveyNumber, setSurveyNumber] = useState('');
  const [mobile, setMobile] = useState('');
  const [language, setLanguage] = useState('mr_in');
  const [captcha, setCaptcha] = useState('');

  // Fetch districts
  useEffect(() => {
    axios.get('/districts/').then(res => setDistricts(res.data));
  }, []);

  // Fetch talukas when district changes
  useEffect(() => {
    if (selectedDistrict) {
      axios.get(`/talukas/${selectedDistrict}/`).then(res => setTalukas(res.data));
    } else {
      setTalukas([]);
      setSelectedTaluka('');
    }
    setVillages([]);
    setSelectedVillage('');
  }, [selectedDistrict]);

  // Fetch villages when taluka changes
  useEffect(() => {
    if (selectedTaluka) {
      axios.get(`/villages/${selectedTaluka}/`).then(res => setVillages(res.data));
    } else {
      setVillages([]);
      setSelectedVillage('');
    }
  }, [selectedTaluka]);

  const handleSubmit = (e) => {
    e.preventDefault();
    axios.post('/search/', {
      district: selectedDistrict,
      taluka: selectedTaluka,
      village: selectedVillage,
      surveyNumber,
      mobile,
      language,
      captcha
    }).then(res => alert(JSON.stringify(res.data)))
      .catch(err => console.error(err));
  };

  return (
    <form onSubmit={handleSubmit} style={{ width: '65%', float: 'right', padding: '20px' }}>
      <h3>७/१२ माहिती (7/12 Details)</h3>

      <div style={{ marginBottom: '10px' }}>
        <label>जिल्हा(District)</label>
        <select
          value={selectedDistrict}
          onChange={e => setSelectedDistrict(e.target.value)}
        >
          <option value="">--निवडा--</option>
          {districts.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
        </select>
      </div>

      <div style={{ marginBottom: '10px' }}>
        <label>तालुका(Taluka)</label>
        <select
          value={selectedTaluka}
          onChange={e => setSelectedTaluka(e.target.value)}
        >
          <option value="">--निवडा--</option>
          {talukas.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
        </select>
      </div>

      <div style={{ marginBottom: '10px' }}>
        <label>गाव(Village)</label>
        <select
          value={selectedVillage}
          onChange={e => setSelectedVillage(e.target.value)}
        >
          <option value="">--निवडा--</option>
          {villages.map(v => <option key={v.id} value={v.id}>{v.name}</option>)}
        </select>
      </div>

      <div style={{ marginBottom: '10px' }}>
        <label>सर्वे नंबर(भाग 1)(Survey Number Part 1)</label>
        <input
          type="text"
          value={surveyNumber}
          onChange={e => setSurveyNumber(e.target.value)}
        />
      </div>

      <div style={{ marginBottom: '10px' }}>
        <label>मोबाईल(Mobile)</label>
        <input
          type="text"
          value={mobile}
          onChange={e => setMobile(e.target.value)}
        />
      </div>

      <div style={{ marginBottom: '10px' }}>
        <label>भाषा निवडा(Select Language)</label>
        <select
          value={language}
          onChange={e => setLanguage(e.target.value)}
        >
          <option value="mr_in">Marathi</option>
          <option value="en_in">English</option>
          <option value="hi_in">Hindi</option>
        </select>
      </div>

      <div style={{ marginBottom: '10px' }}>
        <label>सांकेतिक क्रमांक(Captcha)</label>
        <input
          type="text"
          value={captcha}
          onChange={e => setCaptcha(e.target.value)}
        />
      </div>

      <button type="submit" style={{ marginRight: '10px' }}>Submit</button>
      <button type="reset">Reset</button>
    </form>
  );
};

export default SearchForm;
